var COURSE_TR_DE = [{day: 1, title: `Temel selamlaşmalar`, title_native: `Grundbegrüßungen`, focus: `Berlin’e ilk kez geldiğini düşün. Bugün insanları selamlamayı, kendini kısaca tanıtmayı ve kibarca vedalaşmayı öğreneceksin.`, vocab: [{de: `Hallo`, tr: `Merhaba`, ipa: `ha-lo`},{de: `Guten Morgen`, tr: `Günaydın`, ipa: `guu-tın mor-gın`},{de: `Guten Tag`, tr: `İyi günler`, ipa: `guu-tın taak`},{de: `Guten Abend`, tr: `İyi akşamlar`, ipa: `guu-tın aa-bınt`},{de: `Tschüss`, tr: `Hoşça kal`, ipa: `çüs`},{de: `Bitte`, tr: `Lütfen / buyurun`, ipa: `bi-tı`},{de: `Danke`, tr: `Teşekkürler`, ipa: `dan-kı`},{de: `ja`, tr: `evet`, ipa: `ya`},{de: `nein`, tr: `hayır`, ipa: `nayn`},{de: `ich`, tr: `ben`, ipa: `ih`}], phrases: [{de: `Hallo, ich bin Ali.`, tr: `Merhaba, ben Ali.`, ipa: `ha-lo ih bin a-li`},{de: `Guten Tag, wie geht es Ihnen?`, tr: `İyi günler, nasılsınız?`, ipa: `guu-tın taak vi geet es ii-nın`},{de: `Danke, gut.`, tr: `Teşekkürler, iyiyim.`, ipa: `dan-kı guut`},{de: `Wie heißt du?`, tr: `Senin adın ne?`, ipa: `vi hayst du`},{de: `Ich heiße Ayşe.`, tr: `Benim adım Ayşe.`, ipa: `ih hay-sı ay-şe`},{de: `Tschüss, bis später.`, tr: `Hoşça kal, sonra görüşürüz.`, ipa: `çüs bis şpee-tır`}], grammar: `Almancada “ich” ben demektir ve cümlede genellikle fiilden önce gelir. “Ich bin” ifadesi “ben ...yim” anlamındadır. Resmi ortamlarda “du” yerine “Sie” kullanılır; otelde, restoranda veya mağazada ilk kez konuşurken “Sie” daha güvenlidir.`, practice: [`Almanca “Merhaba, ben [adın]” cümlesini kur.`,`“Teşekkürler, iyiyim” ifadesini üç kez yüksek sesle söyle.`,`Bir arkadaşına “Senin adın ne?” diye Almanca sor.`,`“Günaydın” ve “iyi akşamlar” ifadelerini doğru zamanlarla eşleştir.`,`Resmi bir kişiye selam verirken hangi ifadeyi kullanacağını yaz.`]},{day: 2, title: `Kibar ifadeler ve hayatta kalma cümleleri`, title_native: `Höfliche Ausdrücke und Überlebenssätze`, focus: `Münih’te tren istasyonunda yardıma ihtiyacın var. Bugün lütfen, teşekkürler, özür dilerim ve anlamadım gibi çok gerekli ifadeleri öğreneceksin.`, vocab: [{de: `Entschuldigung`, tr: `Affedersiniz / özür dilerim`, ipa: `ent-şul-di-gung`},{de: `danke schön`, tr: `Çok teşekkürler`, ipa: `dan-kı şön`},{de: `bitte schön`, tr: `Rica ederim / buyurun`, ipa: `bi-tı şön`},{de: `kein Problem`, tr: `Sorun değil`, ipa: `kayn pro-bleem`},{de: `Hilfe`, tr: `Yardım`, ipa: `hil-fı`},{de: `Deutsch`, tr: `Almanca`, ipa: `doytş`},{de: `Türkisch`, tr: `Türkçe`, ipa: `türk-iş`},{de: `Englisch`, tr: `İngilizce`, ipa: `eng-liş`},{de: `langsam`, tr: `yavaş`, ipa: `lang-zam`},{de: `noch einmal`, tr: `bir kez daha`, ipa: `noh ayn-mal`}], phrases: [{de: `Entschuldigung, bitte.`, tr: `Affedersiniz, lütfen.`, ipa: `ent-şul-di-gung bi-tı`},{de: `Ich verstehe nicht.`, tr: `Anlamıyorum.`, ipa: `ih fer-şte-yı niht`},{de: `Sprechen Sie Englisch?`, tr: `İngilizce konuşuyor musunuz?`, ipa: `şpre-hın zi eng-liş`},{de: `Bitte sprechen Sie langsam.`, tr: `Lütfen yavaş konuşun.`, ipa: `bi-tı şpre-hın zi lang-zam`},{de: `Können Sie mir helfen?`, tr: `Bana yardım edebilir misiniz?`, ipa: `kön-nın zi mir hel-fın`},{de: `Noch einmal, bitte.`, tr: `Bir kez daha, lütfen.`, ipa: `noh ayn-mal bi-tı`}], grammar: `Almancada kibar soru sormak için “Können Sie...?” çok kullanışlıdır ve “... yapabilir misiniz?” anlamına gelir. “Sie” resmi “siz” demektir ve fiil çoğunlukla mastar biçimine yakın gelir: “sprechen Sie”, “können Sie”. Seyahatte emin değilsen resmi konuşmak daha naziktir.`, practice: [`“Anlamıyorum” cümlesini Almanca yaz.`,`Bir görevliye “Bana yardım edebilir misiniz?” diye sor.`,`“Lütfen yavaş konuşun” ifadesini yüksek sesle tekrar et.`,`“Deutsch”, “Türkisch” ve “Englisch” kelimelerini kendi dilinde eşleştir.`,`Kibarca bir cümle başlatmak için hangi kelimeyi kullanacağını yaz.`]},{day: 3, title: `Sayılar, fiyatlar ve temel zaman`, title_native: `Zahlen, Preise und einfache Zeit`, focus: `Hamburg’da bir kafede ödeme yaparken fiyatları anlaman gerekiyor. Bugün 0’dan 20’ye sayıları, euro fiyatlarını ve basit saat ifadelerini öğreniyorsun.`, vocab: [{de: `null`, tr: `sıfır`, ipa: `nul`},{de: `eins`, tr: `bir`, ipa: `ayns`},{de: `zwei`, tr: `iki`, ipa: `tsvay`},{de: `drei`, tr: `üç`, ipa: `dray`},{de: `vier`, tr: `dört`, ipa: `fiir`},{de: `fünf`, tr: `beş`, ipa: `fünf`},{de: `sechs`, tr: `altı`, ipa: `zeks`},{de: `sieben`, tr: `yedi`, ipa: `zi-bın`},{de: `acht`, tr: `sekiz`, ipa: `aht`},{de: `zehn`, tr: `on`, ipa: `tseen`}], phrases: [{de: `Wie viel kostet das?`, tr: `Bu ne kadar?`, ipa: `vi fiil kos-tıt das`},{de: `Das kostet fünf Euro.`, tr: `Bu beş euro.`, ipa: `das kos-tıt fünf oy-ro`},{de: `Ich zahle bar.`, tr: `Nakit ödüyorum.`, ipa: `ih tsa-lı baar`},{de: `Ich zahle mit Karte.`, tr: `Kartla ödüyorum.`, ipa: `ih tsa-lı mit kar-tı`},{de: `Um acht Uhr.`, tr: `Saat sekizde.`, ipa: `um aht uur`},{de: `Eine Fahrkarte, bitte.`, tr: `Bir bilet, lütfen.`, ipa: `ay-nı faar-kar-tı bi-tı`}], grammar: `Almancada fiyat sorarken “Wie viel kostet das?” çok temel bir kalıptır. “Das kostet...” ile cevap verilir. Saatlerde “um” belirli saati belirtir: “um acht Uhr” saat sekizde demektir.`, practice: [`1’den 10’a kadar Almanca say.`,`“Bu ne kadar?” cümlesini Almanca yaz.`,`“Bu dört euro” cümlesini kur.`,`“Kartla ödüyorum” ifadesini yüksek sesle söyle.`,`“Saat sekizde” ifadesini kullanarak kısa bir cümle yaz.`]},{day: 4, title: `Kendini tanıtma ve nereli olduğunu söyleme`, title_native: `Sich vorstellen und Herkunft nennen`, focus: `Köln’de hostelde yeni insanlarla tanışıyorsun. Bugün adını, nereden geldiğini ve hangi dili konuştuğunu söylemeyi öğreneceksin.`, vocab: [{de: `Name`, tr: `isim`, ipa: `naa-mı`},{de: `Land`, tr: `ülke`, ipa: `lant`},{de: `Stadt`, tr: `şehir`, ipa: `ştat`},{de: `Türkei`, tr: `Türkiye`, ipa: `tür-kay`},{de: `Deutschland`, tr: `Almanya`, ipa: `doytş-lant`},{de: `Österreich`, tr: `Avusturya`, ipa: `ös-tır-rayh`},{de: `Schweiz`, tr: `İsviçre`, ipa: `şvayts`},{de: `kommen`, tr: `gelmek`, ipa: `ko-mın`},{de: `wohnen`, tr: `yaşamak / oturmak`, ipa: `vo-nın`},{de: `reisen`, tr: `seyahat etmek`, ipa: `ray-zın`}], phrases: [{de: `Ich komme aus der Türkei.`, tr: `Türkiye’den geliyorum.`, ipa: `ih ko-mı aus der tür-kay`},{de: `Ich wohne in Istanbul.`, tr: `İstanbul’da yaşıyorum.`, ipa: `ih vo-nı in is-tan-bul`},{de: `Ich reise allein.`, tr: `Yalnız seyahat ediyorum.`, ipa: `ih ray-zı a-layn`},{de: `Ich reise mit Freunden.`, tr: `Arkadaşlarımla seyahat ediyorum.`, ipa: `ih ray-zı mit froyn-dın`},{de: `Freut mich.`, tr: `Memnun oldum.`, ipa: `froyt mih`},{de: `Woher kommen Sie?`, tr: `Nereden geliyorsunuz?`, ipa: `vo-her ko-mın zi`}], grammar: `“aus” edatı “-den/-dan” anlamına gelir ve ülkelerle çok kullanılır: “aus der Türkei”. Şehirlerde ise “in” kullanılır: “in Istanbul”, “in Berlin”. “Ich komme...” cümlesi seyahatte kendini tanıtırken çok doğal duyulur.`, practice: [`“Türkiye’den geliyorum” cümlesini Almanca yaz.`,`Kendi şehrini kullanarak “...’da yaşıyorum” cümlesi kur.`,`“Nereden geliyorsunuz?” sorusunu resmi biçimde söyle.`,`“Yalnız seyahat ediyorum” ifadesini tekrar et.`,`Yeni tanıştığın birine uygun bir tanışma diyaloğu yaz.`]},{day: 5, title: `Yönler ve şehirde gezinme`, title_native: `Richtungen und Orientierung in der Stadt`, focus: `Viyana’da tarihi merkeze gitmek istiyorsun. Bugün sağ, sol, düz gitmek ve bir yerin nerede olduğunu sormak için temel yön ifadelerini öğreneceksin.`, vocab: [{de: `rechts`, tr: `sağ`, ipa: `rehts`},{de: `links`, tr: `sol`, ipa: `links`},{de: `geradeaus`, tr: `dümdüz`, ipa: `gı-raa-dı-aus`},{de: `hier`, tr: `burada`, ipa: `hiir`},{de: `dort`, tr: `orada`, ipa: `dort`},{de: `nah`, tr: `yakın`, ipa: `naa`},{de: `weit`, tr: `uzak`, ipa: `vayt`},{de: `Straße`, tr: `sokak / cadde`, ipa: `ştraa-sı`},{de: `Platz`, tr: `meydan`, ipa: `plats`},{de: `Karte`, tr: `harita / kart`, ipa: `kar-tı`}], phrases: [{de: `Wo ist der Bahnhof?`, tr: `Tren istasyonu nerede?`, ipa: `vo ist der baan-hoof`},{de: `Gehen Sie geradeaus.`, tr: `Dümdüz gidin.`, ipa: `gee-ın zi gı-raa-dı-aus`},{de: `Dann links.`, tr: `Sonra sola.`, ipa: `dan links`},{de: `Ist es weit?`, tr: `Uzak mı?`, ipa: `ist es vayt`},{de: `Es ist in der Nähe.`, tr: `Yakında.`, ipa: `es ist in der nee-ı`},{de: `Ich suche den Marktplatz.`, tr: `Pazar meydanını arıyorum.`, ipa: `ih zu-hı deyn markt-plats`}], grammar: `Yer sormak için “Wo ist...?” kalıbı kullanılır. “der Bahnhof” gibi isimlerin artikelleri vardır; başlangıçta tüm artikelleri ezberlemek zor olabilir, ama sık kullanılan kelimeleri kalıp halinde öğrenmek çok işe yarar. Yön tariflerinde emir cümleleri genellikle kısa ve nettir.`, practice: [`“Tren istasyonu nerede?” cümlesini Almanca söyle.`,`Sağ, sol ve dümdüz kelimelerini eşleştir.`,`Birine “Uzak mı?” diye Almanca sor.`,`“Dümdüz gidin, sonra sağa” anlamında kısa bir tarif yaz.`,`Haritada bir yer seçip Almanca “... arıyorum” cümlesi kur.`]},{day: 6, title: `Toplu taşıma temelleri`, title_native: `Grundlagen des öffentlichen Verkehrs`, focus: `Zürih’te tramvay ve tren kullanacaksın. Bugün bilet alma, peron bulma ve hangi hatta bineceğini sorma ifadelerini öğreneceksin.`, vocab: [{de: `Bahnhof`, tr: `tren istasyonu`, ipa: `baan-hoof`},{de: `Haltestelle`, tr: `durak`, ipa: `hal-tı-şel-ı`},{de: `Zug`, tr: `tren`, ipa: `tsuuk`},{de: `Bus`, tr: `otobüs`, ipa: `bus`},{de: `Straßenbahn`, tr: `tramvay`, ipa: `ştraa-sın-baan`},{de: `U-Bahn`, tr: `metro`, ipa: `uu-baan`},{de: `Gleis`, tr: `peron / hat`, ipa: `glays`},{de: `Ticket`, tr: `bilet`, ipa: `ti-kıt`},{de: `Fahrplan`, tr: `sefer çizelgesi`, ipa: `faar-plaan`},{de: `Linie`, tr: `hat`, ipa: `li-ni-ı`}], phrases: [{de: `Ich brauche ein Ticket.`, tr: `Bir bilete ihtiyacım var.`, ipa: `ih brau-hı ayn ti-kıt`},{de: `Welche Linie fährt zum Zentrum?`, tr: `Hangi hat merkeze gider?`, ipa: `vel-hı li-ni-ı feert tsum tsen-trum`},{de: `Wo ist Gleis drei?`, tr: `Üçüncü peron nerede?`, ipa: `vo ist glays dray`},{de: `Wann fährt der Zug?`, tr: `Tren ne zaman kalkıyor?`, ipa: `van feert der tsuuk`},{de: `Ist dieses Ticket gültig?`, tr: `Bu bilet geçerli mi?`, ipa: `ist dii-zes ti-kıt gül-tih`},{de: `Ich steige hier aus.`, tr: `Burada iniyorum.`, ipa: `ih ştay-gı hiir aus`}], grammar: `“Welche Linie...?” “hangi hat...?” demektir ve toplu taşımada çok işe yarar. “fahren” fiili araçların gitmesi veya çalışması için kullanılır. “Ich steige aus” ise araçtan iniyorum anlamındadır; “einsteigen” binmek, “aussteigen” inmek demektir.`, practice: [`“Bir bilete ihtiyacım var” cümlesini Almanca yaz.`,`“Tren ne zaman kalkıyor?” sorusunu tekrar et.`,`Kendi hedefin için “Hangi hat ... gider?” cümlesi kur.`,`“Burada iniyorum” ifadesini kullanarak kısa bir cümle yaz.`,`Bilet görevlisine geçerli bilet sorusu hazırlayın.`]},{day: 7, title: `Kafede sipariş verme`, title_native: `Im Café bestellen`, focus: `Salzburg’da küçük bir kafeye girdin. Bugün kahve, su, tatlı sipariş etmeyi ve hesabı istemeyi öğreneceksin.`, vocab: [{de: `Kaffee`, tr: `kahve`, ipa: `ka-fe`},{de: `Tee`, tr: `çay`, ipa: `tee`},{de: `Wasser`, tr: `su`, ipa: `va-sır`},{de: `Milch`, tr: `süt`, ipa: `milh`},{de: `Zucker`, tr: `şeker`, ipa: `tsu-kır`},{de: `Kuchen`, tr: `kek / pasta`, ipa: `kuu-hın`},{de: `Brot`, tr: `ekmek`, ipa: `broot`},{de: `Tasse`, tr: `fincan`, ipa: `ta-sı`},{de: `Rechnung`, tr: `hesap`, ipa: `reh-nung`},{de: `Café`, tr: `kafe`, ipa: `ka-fe`}], phrases: [{de: `Einen Kaffee, bitte.`, tr: `Bir kahve, lütfen.`, ipa: `ay-nın ka-fe bi-tı`},{de: `Ich hätte gern einen Tee.`, tr: `Bir çay almak isterim.`, ipa: `ih het-ı gern ay-nın tee`},{de: `Mit Milch, bitte.`, tr: `Sütlü olsun, lütfen.`, ipa: `mit milh bi-tı`},{de: `Ohne Zucker, bitte.`, tr: `Şekersiz olsun, lütfen.`, ipa: `oo-nı tsu-kır bi-tı`},{de: `Kann ich zahlen?`, tr: `Ödeyebilir miyim?`, ipa: `kan ih tsa-lın`},{de: `Die Rechnung, bitte.`, tr: `Hesap, lütfen.`, ipa: `di reh-nung bi-tı`}], grammar: `Sipariş verirken “Ich hätte gern...” çok kibar ve doğal bir kalıptır. Türkçedeki “... almak isterim” gibi çalışır. “mit” ile “ile”, “ohne” ile “-siz” anlamı verilir: “mit Milch”, “ohne Zucker”.`, practice: [`“Bir kahve, lütfen” cümlesini Almanca söyle.`,`“Şekersiz” ve “sütlü” ifadelerini karşılaştır.`,`“Bir çay almak isterim” cümlesini yaz.`,`Hesap istemek için iki farklı ifade kullan.`,`Kendi sevdiğin içecekle kısa bir sipariş cümlesi kur.`]},{day: 8, title: `Restoranda yemek seçmek`, title_native: `Im Restaurant Essen auswählen`, focus: `Frankfurt’ta geleneksel bir restorandasın. Menü sormayı, yemek seçmeyi ve alerji ya da tercih belirtmeyi öğreneceksin.`, vocab: [{de: `Speisekarte`, tr: `menü`, ipa: `şpay-zı-kar-tı`},{de: `Gericht`, tr: `yemek`, ipa: `gı-riht`},{de: `Fleisch`, tr: `et`, ipa: `flayş`},{de: `Fisch`, tr: `balık`, ipa: `fiş`},{de: `Gemüse`, tr: `sebze`, ipa: `gı-mü-zı`},{de: `Salat`, tr: `salata`, ipa: `za-laat`},{de: `Suppe`, tr: `çorba`, ipa: `zu-pı`},{de: `vegetarisch`, tr: `vejetaryen`, ipa: `ve-ge-taa-riş`},{de: `scharf`, tr: `acı`, ipa: `şarf`},{de: `lecker`, tr: `lezzetli`, ipa: `le-kır`}], phrases: [{de: `Die Speisekarte, bitte.`, tr: `Menü, lütfen.`, ipa: `di şpay-zı-kar-tı bi-tı`},{de: `Was empfehlen Sie?`, tr: `Ne önerirsiniz?`, ipa: `vas emp-fee-lın zi`},{de: `Ich esse kein Fleisch.`, tr: `Et yemiyorum.`, ipa: `ih es-ı kayn flayş`},{de: `Ist das vegetarisch?`, tr: `Bu vejetaryen mi?`, ipa: `ist das ve-ge-taa-riş`},{de: `Nicht zu scharf, bitte.`, tr: `Çok acı olmasın, lütfen.`, ipa: `niht tsu şarf bi-tı`},{de: `Das war sehr lecker.`, tr: `Çok lezzetliydi.`, ipa: `das vaar zeer le-kır`}], grammar: `Almancada “kein” bir ismi olumsuz yapmak için kullanılır: “kein Fleisch” et yok / et değil anlamındadır. “Ich esse kein Fleisch” seyahatte çok pratik bir cümledir. “Nicht zu...” ise “çok ... olmasın” anlamında kullanılır.`, practice: [`“Menü, lütfen” cümlesini söyle.`,`“Et yemiyorum” cümlesini Almanca yaz.`,`Bir garsona “Ne önerirsiniz?” diye sor.`,`“Bu vejetaryen mi?” cümlesini tekrar et.`,`Yediğin bir yemek için “Çok lezzetliydi” cümlesi kur.`]},{day: 9, title: `Otelde giriş yapmak`, title_native: `Im Hotel einchecken`, focus: `Düsseldorf’ta oteline varıyorsun. Bugün rezervasyon, pasaport, oda anahtarı ve kahvaltı saatleri gibi otel ifadelerini öğreneceksin.`, vocab: [{de: `Hotel`, tr: `otel`, ipa: `ho-tel`},{de: `Reservierung`, tr: `rezervasyon`, ipa: `re-zer-vi-rung`},{de: `Zimmer`, tr: `oda`, ipa: `tsi-mır`},{de: `Schlüssel`, tr: `anahtar`, ipa: `şlü-sıl`},{de: `Pass`, tr: `pasaport`, ipa: `pas`},{de: `Frühstück`, tr: `kahvaltı`, ipa: `frü-ştük`},{de: `Nacht`, tr: `gece`, ipa: `naht`},{de: `Aufzug`, tr: `asansör`, ipa: `auf-tsuuk`},{de: `Empfang`, tr: `resepsiyon`, ipa: `emp-fang`},{de: `WLAN`, tr: `Wi-Fi`, ipa: `ve-lan`}], phrases: [{de: `Ich habe eine Reservierung.`, tr: `Rezervasyonum var.`, ipa: `ih haa-bı ay-nı re-zer-vi-rung`},{de: `Auf den Namen Yılmaz.`, tr: `Yılmaz adına.`, ipa: `auf deyn naa-mın yıl-maz`},{de: `Kann ich einchecken?`, tr: `Giriş yapabilir miyim?`, ipa: `kan ih ayn-çek-ın`},{de: `Wo ist mein Zimmer?`, tr: `Odam nerede?`, ipa: `vo ist mayn tsi-mır`},{de: `Gibt es WLAN?`, tr: `Wi-Fi var mı?`, ipa: `gibt es ve-lan`},{de: `Wann ist Frühstück?`, tr: `Kahvaltı ne zaman?`, ipa: `van ist frü-ştük`}], grammar: `“Gibt es...?” Almancada “var mı?” demenin en kullanışlı yoludur. “Gibt es WLAN?” veya “Gibt es Frühstück?” gibi birçok durumda kullanılabilir. Otelde “auf den Namen...” rezervasyon adını belirtmek için yaygın bir kalıptır.`, practice: [`“Rezervasyonum var” cümlesini Almanca söyle.`,`Kendi soyadınla “... adına” ifadesi kur.`,`“Wi-Fi var mı?” sorusunu yaz.`,`Resepsiyona “Kahvaltı ne zaman?” diye sor.`,`Otel girişinde kullanacağın üç cümleyi sırala.`]},{day: 10, title: `Alışveriş ve mağazada soru sorma`, title_native: `Einkaufen und Fragen im Geschäft`, focus: `Stuttgart’ta bir mağazada hediye almak istiyorsun. Bugün beden, renk, fiyat ve ödeme yöntemleri hakkında soru sormayı öğreneceksin.`, vocab: [{de: `Geschäft`, tr: `mağaza`, ipa: `gı-şeft`},{de: `Preis`, tr: `fiyat`, ipa: `prays`},{de: `Größe`, tr: `beden / boyut`, ipa: `grö-sı`},{de: `Farbe`, tr: `renk`, ipa: `far-bı`},{de: `rot`, tr: `kırmızı`, ipa: `root`},{de: `blau`, tr: `mavi`, ipa: `blau`},{de: `schwarz`, tr: `siyah`, ipa: `şvarts`},{de: `weiß`, tr: `beyaz`, ipa: `vays`},{de: `billig`, tr: `ucuz`, ipa: `bi-lih`},{de: `teuer`, tr: `pahalı`, ipa: `toy-ır`}], phrases: [{de: `Ich suche ein Geschenk.`, tr: `Bir hediye arıyorum.`, ipa: `ih zu-hı ayn gı-şenk`},{de: `Haben Sie das in Blau?`, tr: `Bunun mavisi var mı?`, ipa: `haa-bın zi das in blau`},{de: `Welche Größe ist das?`, tr: `Bu hangi beden?`, ipa: `vel-hı grö-sı ist das`},{de: `Das ist zu teuer.`, tr: `Bu çok pahalı.`, ipa: `das ist tsu toy-ır`},{de: `Kann ich mit Karte zahlen?`, tr: `Kartla ödeyebilir miyim?`, ipa: `kan ih mit kar-tı tsa-lın`},{de: `Ich nehme das.`, tr: `Bunu alıyorum.`, ipa: `ih nee-mı das`}], grammar: `Alışverişte “Ich suche...” çok işe yarar; “... arıyorum” anlamındadır. “Haben Sie...?” resmi ve pratik bir soru kalıbıdır. “Ich nehme das” ise karar verdiğinde kullanılan doğal bir ifadedir.`, practice: [`“Bir hediye arıyorum” cümlesini Almanca yaz.`,`Üç renk kelimesini Almanca söyle.`,`“Bunun mavisi var mı?” sorusunu tekrar et.`,`“Bu çok pahalı” cümlesini kur.`,`Kendi almak istediğin bir ürün için mağaza diyaloğu yaz.`]},{day: 11, title: `Günler, tarihler ve plan yapmak`, title_native: `Tage, Daten und Pläne machen`, focus: `Leipzig’de müze ziyareti planlıyorsun. Bugün haftanın günlerini, bugün-yarın ifadelerini ve basit plan cümlelerini öğreneceksin.`, vocab: [{de: `Montag`, tr: `pazartesi`, ipa: `moon-taak`},{de: `Dienstag`, tr: `salı`, ipa: `diins-taak`},{de: `Mittwoch`, tr: `çarşamba`, ipa: `mit-voh`},{de: `Donnerstag`, tr: `perşembe`, ipa: `do-nırs-taak`},{de: `Freitag`, tr: `cuma`, ipa: `fray-taak`},{de: `Samstag`, tr: `cumartesi`, ipa: `zam-staak`},{de: `Sonntag`, tr: `pazar`, ipa: `zon-taak`},{de: `heute`, tr: `bugün`, ipa: `hoy-tı`},{de: `morgen`, tr: `yarın`, ipa: `mor-gın`},{de: `gestern`, tr: `dün`, ipa: `ges-tırn`}], phrases: [{de: `Heute ist Montag.`, tr: `Bugün pazartesi.`, ipa: `hoy-tı ist moon-taak`},{de: `Morgen gehe ich ins Museum.`, tr: `Yarın müzeye gidiyorum.`, ipa: `mor-gın gee-ı ih ins mu-zee-um`},{de: `Wann haben Sie geöffnet?`, tr: `Ne zaman açıksınız?`, ipa: `van haa-bın zi gı-öf-nıt`},{de: `Am Freitag.`, tr: `Cuma günü.`, ipa: `am fray-taak`},{de: `Ich habe Zeit.`, tr: `Vaktim var.`, ipa: `ih haa-bı tsayt`},{de: `Ich habe keine Zeit.`, tr: `Vaktim yok.`, ipa: `ih haa-bı kay-nı tsayt`}], grammar: `Günlerle “am” kullanılır: “am Freitag” cuma günü demektir. “heute”, “morgen” ve “gestern” cümle başında kullanıldığında planları açıkça belirtir. Almancada fiil genellikle ikinci pozisyonda durur: “Morgen gehe ich...”`, practice: [`Haftanın günlerini Almanca sırayla say.`,`“Yarın müzeye gidiyorum” cümlesini yaz.`,`“Ne zaman açıksınız?” sorusunu tekrar et.`,`“Vaktim yok” cümlesini Almanca söyle.`,`Kendi haftalık planından üç kısa Almanca cümle kur.`]},{day: 12, title: `Saatler ve randevular`, title_native: `Uhrzeiten und Termine`, focus: `Hannover’de bir tur rezervasyonuna yetişmen gerekiyor. Bugün saat sormayı, randevu saatini belirtmeyi ve geç kaldığını söylemeyi öğreneceksin.`, vocab: [{de: `Uhr`, tr: `saat`, ipa: `uur`},{de: `Minute`, tr: `dakika`, ipa: `mi-nuu-tı`},{de: `halb`, tr: `buçuk`, ipa: `halp`},{de: `Viertel`, tr: `çeyrek`, ipa: `fiir-tıl`},{de: `Termin`, tr: `randevu`, ipa: `ter-miin`},{de: `früh`, tr: `erken`, ipa: `früü`},{de: `spät`, tr: `geç`, ipa: `şpeet`},{de: `pünktlich`, tr: `dakik`, ipa: `pünkt-lih`},{de: `warten`, tr: `beklemek`, ipa: `var-tın`},{de: `jetzt`, tr: `şimdi`, ipa: `yetst`}], phrases: [{de: `Wie spät ist es?`, tr: `Saat kaç?`, ipa: `vi şpeet ist es`},{de: `Es ist neun Uhr.`, tr: `Saat dokuz.`, ipa: `es ist noyn uur`},{de: `Der Termin ist um zehn.`, tr: `Randevu saat onda.`, ipa: `der ter-miin ist um tseen`},{de: `Ich bin zu spät.`, tr: `Geç kaldım.`, ipa: `ih bin tsu şpeet`},{de: `Bitte warten Sie.`, tr: `Lütfen bekleyin.`, ipa: `bi-tı var-tın zi`},{de: `Ich bin pünktlich.`, tr: `Dakikim.`, ipa: `ih bin pünkt-lih`}], grammar: `Saat söylerken “Es ist...” kullanılır: “Es ist neun Uhr.” Belirli bir saatte olan etkinlik için “um” kullanılır: “um zehn”. “zu spät” geç kalmış, “pünktlich” dakik anlamındadır ve seyahatte önemlidir.`, practice: [`“Saat kaç?” sorusunu Almanca yaz.`,`“Saat dokuz” cümlesini söyle.`,`“Randevu saat onda” cümlesini kur.`,`“Geç kaldım” ifadesini üç kez tekrar et.`,`Kendi gününden iki randevu saati yaz.`]},{day: 13, title: `Aile, arkadaşlar ve insanlar`, title_native: `Familie, Freunde und Menschen`, focus: `Graz’da yerel biriyle sohbet ederken yanında kimlerle seyahat ettiğini anlatıyorsun. Bugün aile ve arkadaş kelimelerini öğreniyorsun.`, vocab: [{de: `Familie`, tr: `aile`, ipa: `fa-mi-li-ı`},{de: `Freund`, tr: `erkek arkadaş / dost`, ipa: `froynt`},{de: `Freundin`, tr: `kadın arkadaş / kız arkadaş`, ipa: `froyn-din`},{de: `Mutter`, tr: `anne`, ipa: `mu-tır`},{de: `Vater`, tr: `baba`, ipa: `faa-tır`},{de: `Bruder`, tr: `erkek kardeş`, ipa: `bru-dır`},{de: `Schwester`, tr: `kız kardeş`, ipa: `şves-tır`},{de: `Kind`, tr: `çocuk`, ipa: `kint`},{de: `Mann`, tr: `adam / eş`, ipa: `man`},{de: `Frau`, tr: `kadın / eş`, ipa: `frau`}], phrases: [{de: `Das ist mein Freund.`, tr: `Bu benim arkadaşım.`, ipa: `das ist mayn froynt`},{de: `Das ist meine Freundin.`, tr: `Bu benim arkadaşım.`, ipa: `das ist may-nı froyn-din`},{de: `Ich bin mit meiner Familie hier.`, tr: `Burada ailemle birlikteyim.`, ipa: `ih bin mit may-nır fa-mi-li-ı hiir`},{de: `Haben Sie Kinder?`, tr: `Çocuğunuz var mı?`, ipa: `haa-bın zi kin-dır`},{de: `Meine Mutter ist in der Türkei.`, tr: `Annem Türkiye’de.`, ipa: `may-nı mu-tır ist in der tür-kay`},{de: `Wir sind Freunde.`, tr: `Biz arkadaşız.`, ipa: `viir zint froyn-dı`}], grammar: `Almancada “mein” ve “meine” sahiplik bildirir. Kelimenin cinsine göre değişir: “mein Freund”, “meine Freundin”. Başlangıçta bu değişimler zor görünür, ama kalıp halinde öğrenmek konuşmayı hızlandırır.`, practice: [`“Bu benim arkadaşım” cümlesini iki biçimde yaz.`,`“Burada ailemle birlikteyim” ifadesini söyle.`,`Aile üyelerinden beşini Almanca listele.`,`“Çocuğunuz var mı?” sorusunu resmi biçimde tekrar et.`,`Kendi ailen hakkında iki basit Almanca cümle kur.`]},{day: 14, title: `Hava durumu ve kıyafetler`, title_native: `Wetter und Kleidung`, focus: `Basel’de hava değişken; sabah yağmur, öğleden sonra güneş var. Bugün hava durumunu anlamayı ve uygun kıyafetleri konuşmayı öğreneceksin.`, vocab: [{de: `Wetter`, tr: `hava durumu`, ipa: `ve-tır`},{de: `Sonne`, tr: `güneş`, ipa: `zo-nı`},{de: `Regen`, tr: `yağmur`, ipa: `ree-gın`},{de: `Schnee`, tr: `kar`, ipa: `şnee`},{de: `Wind`, tr: `rüzgar`, ipa: `vint`},{de: `kalt`, tr: `soğuk`, ipa: `kalt`},{de: `warm`, tr: `sıcak`, ipa: `varm`},{de: `Jacke`, tr: `ceket`, ipa: `ya-kı`},{de: `Schuhe`, tr: `ayakkabılar`, ipa: `şuu-ı`},{de: `Regenschirm`, tr: `şemsiye`, ipa: `ree-gın-şirm`}], phrases: [{de: `Wie ist das Wetter?`, tr: `Hava nasıl?`, ipa: `vi ist das ve-tır`},{de: `Es ist kalt.`, tr: `Hava soğuk.`, ipa: `es ist kalt`},{de: `Es regnet.`, tr: `Yağmur yağıyor.`, ipa: `es ree-gnıt`},{de: `Ich brauche eine Jacke.`, tr: `Bir cekete ihtiyacım var.`, ipa: `ih brau-hı ay-nı ya-kı`},{de: `Haben Sie einen Regenschirm?`, tr: `Şemsiyeniz var mı?`, ipa: `haa-bın zi ay-nın ree-gın-şirm`},{de: `Heute ist es warm.`, tr: `Bugün hava sıcak.`, ipa: `hoy-tı ist es varm`}], grammar: `Hava durumunda Almancada çoğunlukla “es” kullanılır: “Es regnet”, “Es ist kalt”. Bu “es” Türkçeye doğrudan çevrilmez ama cümlede gereklidir. “Ich brauche...” bir şeye ihtiyaç duyduğunu söylemek için çok pratik bir kalıptır.`, practice: [`“Hava nasıl?” cümlesini Almanca sor.`,`“Yağmur yağıyor” ifadesini söyle.`,`“Bir cekete ihtiyacım var” cümlesini yaz.`,`Kıyafetlerden üç kelimeyi Almanca listele.`,`Bugünkü hava için Almanca bir cümle kur.`]},{day: 15, title: `Sağlık ve eczane`, title_native: `Gesundheit und Apotheke`, focus: `Nürnberg’de başın ağrıyor ve eczaneye gitmen gerekiyor. Bugün sağlık şikâyetlerini ve eczanede yardım istemeyi öğreneceksin.`, vocab: [{de: `Apotheke`, tr: `eczane`, ipa: `a-po-tee-kı`},{de: `Arzt`, tr: `doktor`, ipa: `artst`},{de: `Schmerz`, tr: `ağrı`, ipa: `şmerts`},{de: `Kopfschmerzen`, tr: `baş ağrısı`, ipa: `kopf-şmer-tsın`},{de: `Bauchschmerzen`, tr: `karın ağrısı`, ipa: `bauh-şmer-tsın`},{de: `Medizin`, tr: `ilaç`, ipa: `me-di-tsiin`},{de: `Tablette`, tr: `tablet`, ipa: `ta-ble-tı`},{de: `Allergie`, tr: `alerji`, ipa: `a-ler-gii`},{de: `krank`, tr: `hasta`, ipa: `krank`},{de: `Notfall`, tr: `acil durum`, ipa: `noot-fal`}], phrases: [{de: `Ich brauche eine Apotheke.`, tr: `Bir eczaneye ihtiyacım var.`, ipa: `ih brau-hı ay-nı a-po-tee-kı`},{de: `Ich habe Kopfschmerzen.`, tr: `Başım ağrıyor.`, ipa: `ih haa-bı kopf-şmer-tsın`},{de: `Mir ist schlecht.`, tr: `Midem bulanıyor / kendimi kötü hissediyorum.`, ipa: `mir ist şleht`},{de: `Ich habe eine Allergie.`, tr: `Alerjim var.`, ipa: `ih haa-bı ay-nı a-ler-gii`},{de: `Gibt es einen Arzt in der Nähe?`, tr: `Yakında doktor var mı?`, ipa: `gibt es ay-nın artst in der nee-ı`},{de: `Es ist ein Notfall.`, tr: `Bu acil bir durum.`, ipa: `es ist ayn noot-fal`}], grammar: `Ağrılar için Almancada çoğu zaman “Ich habe...” kullanılır: “Ich habe Kopfschmerzen.” “Mir ist schlecht” ise “kendimi kötü hissediyorum” anlamında kalıp bir ifadedir. Sağlık durumlarında kısa ve net konuşmak en güvenlisidir.`, practice: [`“Başım ağrıyor” cümlesini Almanca yaz.`,`“Bir eczaneye ihtiyacım var” ifadesini tekrar et.`,`“Alerjim var” cümlesini söyle.`,`“Yakında doktor var mı?” sorusunu kur.`,`Acil durumda kullanacağın iki Almanca cümleyi listele.`]},{day: 16, title: `Acil durumlar ve güvenlik`, title_native: `Notfälle und Sicherheit`, focus: `Dresden’de çantanı kaybettin veya yardıma ihtiyacın var. Bugün polis, kayıp eşya, yardım ve acil durum ifadelerini öğreneceksin.`, vocab: [{de: `Polizei`, tr: `polis`, ipa: `po-li-tsay`},{de: `Krankenhaus`, tr: `hastane`, ipa: `kran-kın-haus`},{de: `Tasche`, tr: `çanta`, ipa: `ta-şı`},{de: `Handy`, tr: `cep telefonu`, ipa: `hen-di`},{de: `Pass`, tr: `pasaport`, ipa: `pas`},{de: `verloren`, tr: `kayıp / kaybetmiş`, ipa: `fer-loo-rın`},{de: `gestohlen`, tr: `çalınmış`, ipa: `gı-ştoo-lın`},{de: `Hilfe`, tr: `yardım`, ipa: `hil-fı`},{de: `gefährlich`, tr: `tehlikeli`, ipa: `gı-feer-lih`},{de: `sicher`, tr: `güvenli`, ipa: `zi-hır`}], phrases: [{de: `Ich habe meine Tasche verloren.`, tr: `Çantamı kaybettim.`, ipa: `ih haa-bı may-nı ta-şı fer-loo-rın`},{de: `Mein Handy wurde gestohlen.`, tr: `Telefonum çalındı.`, ipa: `mayn hen-di vur-dı gı-ştoo-lın`},{de: `Rufen Sie die Polizei!`, tr: `Polisi arayın!`, ipa: `ruu-fın zi di po-li-tsay`},{de: `Ich brauche Hilfe.`, tr: `Yardıma ihtiyacım var.`, ipa: `ih brau-hı hil-fı`},{de: `Ist dieser Ort sicher?`, tr: `Burası güvenli mi?`, ipa: `ist dii-zır ort zi-hır`},{de: `Wo ist das Krankenhaus?`, tr: `Hastane nerede?`, ipa: `vo ist das kran-kın-haus`}], grammar: `Acil durumlarda uzun cümleler kurmaya gerek yoktur; “Ich brauche Hilfe” en önemli cümlelerden biridir. “verloren” kaybetmiş, “gestohlen” çalınmış anlamında kullanılır. Resmi emirlerde “Rufen Sie...” gibi “Sie” biçimi kullanılır.`, practice: [`“Yardıma ihtiyacım var” cümlesini ezberle.`,`“Çantamı kaybettim” cümlesini yaz.`,`“Polisi arayın!” ifadesini yüksek sesle söyle.`,`“Burası güvenli mi?” sorusunu kur.`,`Pasaportunu kaybettiğini anlatan kısa bir Almanca cümle yaz.`]},{day: 17, title: `Biletler, müzeler ve turistik yerler`, title_native: `Tickets, Museen und Sehenswürdigkeiten`, focus: `Berlin’de müze adasına gidiyorsun. Bugün giriş bileti alma, indirim sorma ve açılış saatlerini öğrenme ifadelerini çalışacaksın.`, vocab: [{de: `Museum`, tr: `müze`, ipa: `mu-zee-um`},{de: `Eintritt`, tr: `giriş`, ipa: `ayn-trit`},{de: `Ticket`, tr: `bilet`, ipa: `ti-kıt`},{de: `Ermäßigung`, tr: `indirim`, ipa: `er-me-si-gung`},{de: `Student`, tr: `öğrenci`, ipa: `ştu-dent`},{de: `Ausstellung`, tr: `sergi`, ipa: `aus-ştel-lung`},{de: `Führung`, tr: `rehberli tur`, ipa: `fü-rung`},{de: `geöffnet`, tr: `açık`, ipa: `gı-öf-nıt`},{de: `geschlossen`, tr: `kapalı`, ipa: `gı-şlo-sın`},{de: `Sehenswürdigkeit`, tr: `görülecek yer`, ipa: `zee-ıns-vür-dih-kayt`}], phrases: [{de: `Ein Ticket, bitte.`, tr: `Bir bilet, lütfen.`, ipa: `ayn ti-kıt bi-tı`},{de: `Gibt es eine Ermäßigung?`, tr: `İndirim var mı?`, ipa: `gibt es ay-nı er-me-si-gung`},{de: `Ich bin Student.`, tr: `Öğrenciyim.`, ipa: `ih bin ştu-dent`},{de: `Wann schließt das Museum?`, tr: `Müze ne zaman kapanıyor?`, ipa: `van şliist das mu-zee-um`},{de: `Ist die Führung auf Englisch?`, tr: `Rehberli tur İngilizce mi?`, ipa: `ist di fü-rung auf eng-liş`},{de: `Die Ausstellung ist interessant.`, tr: `Sergi ilginç.`, ipa: `di aus-ştel-lung ist in-te-re-sant`}], grammar: `“Gibt es...?” yine “var mı?” anlamında kullanılır ve indirim, rehberli tur veya bilet sorarken çok işe yarar. “geöffnet” açık, “geschlossen” kapalı anlamındadır. Açılış-kapanış saatlerinde “Wann öffnet...?” ve “Wann schließt...?” soruları kullanılır.`, practice: [`“Bir bilet, lütfen” cümlesini söyle.`,`“İndirim var mı?” sorusunu Almanca yaz.`,`“Müze ne zaman kapanıyor?” cümlesini kur.`,`“Sergi ilginç” ifadesini tekrar et.`,`Bir müze görevlisiyle kısa bir bilet alma diyaloğu yaz.`]},{day: 18, title: `Tren yolculuğu ve şehirler arası seyahat`, title_native: `Zugreise und Reisen zwischen Städten`, focus: `Köln’den Amsterdam’a veya Münih’ten Viyana’ya trenle gidiyorsun. Bugün şehirler arası bilet, aktarma ve koltuk rezervasyonu ifadelerini öğreneceksin.`, vocab: [{de: `Reise`, tr: `yolculuk`, ipa: `ray-zı`},{de: `Abfahrt`, tr: `kalkış`, ipa: `ap-faart`},{de: `Ankunft`, tr: `varış`, ipa: `an-kunft`},{de: `Umstieg`, tr: `aktarma`, ipa: `um-ştiik`},{de: `Sitzplatz`, tr: `koltuk`, ipa: `zits-plats`},{de: `Reservierung`, tr: `rezervasyon`, ipa: `re-zer-vi-rung`},{de: `Wagen`, tr: `vagon`, ipa: `va-gın`},{de: `Verspätung`, tr: `gecikme`, ipa: `fer-şpee-tung`},{de: `direkt`, tr: `direkt`, ipa: `di-rekt`},{de: `Hin und zurück`, tr: `gidiş dönüş`, ipa: `hin unt tsu-rük`}], phrases: [{de: `Ich möchte nach Wien fahren.`, tr: `Viyana’ya gitmek istiyorum.`, ipa: `ih möh-tı nah viin faa-rın`},{de: `Gibt es einen direkten Zug?`, tr: `Direkt tren var mı?`, ipa: `gibt es ay-nın di-rek-tın tsuuk`},{de: `Muss ich umsteigen?`, tr: `Aktarma yapmam gerekiyor mu?`, ipa: `mus ih um-ştay-gın`},{de: `Ich habe eine Sitzplatzreservierung.`, tr: `Koltuk rezervasyonum var.`, ipa: `ih haa-bı ay-nı zits-plats-re-zer-vi-rung`},{de: `Der Zug hat Verspätung.`, tr: `Tren gecikmeli.`, ipa: `der tsuuk hat fer-şpee-tung`},{de: `Eine Fahrkarte hin und zurück, bitte.`, tr: `Gidiş dönüş bilet, lütfen.`, ipa: `ay-nı faar-kar-tı hin unt tsu-rük bi-tı`}], grammar: `Bir yere gitmek istediğini söylemek için “Ich möchte nach...” kullanılır. Şehir adlarından önce genellikle “nach” gelir: “nach Wien”, “nach Berlin”. “Muss ich...?” ise “... yapmam gerekiyor mu?” anlamındadır.`, practice: [`Gitmek istediğin bir şehirle “Ich möchte nach...” cümlesi kur.`,`“Direkt tren var mı?” sorusunu yaz.`,`“Aktarma yapmam gerekiyor mu?” ifadesini söyle.`,`“Tren gecikmeli” cümlesini tekrar et.`,`Gidiş dönüş bilet almak için Almanca bir cümle yaz.`]},{day: 19, title: `Telefonda ve çevrim içi rezervasyon`, title_native: `Am Telefon und online reservieren`, focus: `Hamburg’da popüler bir restoran için telefonla veya internetten rezervasyon yapmak istiyorsun. Bugün tarih, saat, kişi sayısı ve iletişim bilgisi vermeyi öğreneceksin.`, vocab: [{de: `anrufen`, tr: `aramak`, ipa: `an-ruu-fın`},{de: `Reservierung`, tr: `rezervasyon`, ipa: `re-zer-vi-rung`},{de: `Person`, tr: `kişi`, ipa: `per-zoon`},{de: `Telefonnummer`, tr: `telefon numarası`, ipa: `te-le-foon-num-ır`},{de: `E-Mail`, tr: `e-posta`, ipa: `ii-meyl`},{de: `frei`, tr: `müsait / boş`, ipa: `fray`},{de: `besetzt`, tr: `dolu / meşgul`, ipa: `bı-zetst`},{de: `bestätigen`, tr: `onaylamak`, ipa: `bı-şte-ti-gın`},{de: `ändern`, tr: `değiştirmek`, ipa: `en-dırn`},{de: `stornieren`, tr: `iptal etmek`, ipa: `ştor-nii-rın`}], phrases: [{de: `Ich möchte reservieren.`, tr: `Rezervasyon yapmak istiyorum.`, ipa: `ih möh-tı re-zer-vii-rın`},{de: `Für zwei Personen, bitte.`, tr: `İki kişi için, lütfen.`, ipa: `für tsvay per-zoo-nın bi-tı`},{de: `Haben Sie heute Abend frei?`, tr: `Bu akşam yeriniz var mı?`, ipa: `haa-bın zi hoy-tı aa-bınt fray`},{de: `Kann ich die Reservierung ändern?`, tr: `Rezervasyonu değiştirebilir miyim?`, ipa: `kan ih di re-zer-vi-rung en-dırn`},{de: `Ich möchte stornieren.`, tr: `İptal etmek istiyorum.`, ipa: `ih möh-tı ştor-nii-rın`},{de: `Können Sie das bestätigen?`, tr: `Bunu onaylayabilir misiniz?`, ipa: `kön-nın zi das bı-şte-ti-gın`}], grammar: `“möchte” nazik istek belirtir ve seyahatte çok sık kullanılır: “Ich möchte reservieren.” Kişi sayısını belirtirken “für zwei Personen” denir. Rezervasyonla ilgili fiiller doğrudan çok işe yarar: “ändern” değiştirmek, “stornieren” iptal etmek.`, practice: [`“Rezervasyon yapmak istiyorum” cümlesini Almanca yaz.`,`“İki kişi için” ifadesini üç farklı sayı ile değiştir.`,`“Bu akşam yeriniz var mı?” sorusunu söyle.`,`Bir rezervasyonu iptal etmek için kısa bir cümle kur.`,`Telefonla rezervasyon için dört satırlık mini diyalog yaz.`]},{day: 20, title: `Ev, konaklama ve günlük ihtiyaçlar`, title_native: `Wohnung, Unterkunft und tägliche Bedürfnisse`, focus: `Berlin’de kısa dönem kiralık bir dairede kalıyorsun. Bugün ev eşyaları, sorun bildirme ve temel ihtiyaç ifadelerini öğreneceksin.`, vocab: [{de: `Wohnung`, tr: `daire`, ipa: `voo-nung`},{de: `Küche`, tr: `mutfak`, ipa: `kü-hı`},{de: `Bad`, tr: `banyo`, ipa: `baat`},{de: `Bett`, tr: `yatak`, ipa: `bet`},{de: `Tür`, tr: `kapı`, ipa: `tüür`},{de: `Fenster`, tr: `pencere`, ipa: `fens-tır`},{de: `Heizung`, tr: `ısıtma`, ipa: `hay-tsung`},{de: `Schlüssel`, tr: `anahtar`, ipa: `şlü-sıl`},{de: `kaputt`, tr: `bozuk`, ipa: `ka-put`},{de: `sauber`, tr: `temiz`, ipa: `zau-bır`}], phrases: [{de: `Die Heizung ist kaputt.`, tr: `Isıtma bozuk.`, ipa: `di hay-tsung ist ka-put`},{de: `Ich brauche einen Schlüssel.`, tr: `Bir anahtara ihtiyacım var.`, ipa: `ih brau-hı ay-nın şlü-sıl`},{de: `Das Zimmer ist sauber.`, tr: `Oda temiz.`, ipa: `das tsi-mır ist zau-bır`},{de: `Das Fenster geht nicht auf.`, tr: `Pencere açılmıyor.`, ipa: `das fens-tır geet niht auf`},{de: `Gibt es eine Küche?`, tr: `Mutfak var mı?`, ipa: `gibt es ay-nı kü-hı`},{de: `Ich bleibe drei Nächte.`, tr: `Üç gece kalıyorum.`, ipa: `ih blay-bı dray neh-tı`}], grammar: `Ev veya oda sorunlarında “ist kaputt” çok basit ve net bir ifadedir. “geht nicht auf” açılmıyor, “geht nicht zu” kapanmıyor anlamında kullanılabilir. Konaklama süresini belirtirken “Ich bleibe...” kalıbı kullanılır.`, practice: [`“Isıtma bozuk” cümlesini Almanca söyle.`,`“Mutfak var mı?” sorusunu yaz.`,`“Üç gece kalıyorum” cümlesini kendi sayınla değiştir.`,`Evdeki beş eşyayı Almanca listele.`,`Bir daire sorununu bildiren kısa bir mesaj yaz.`]},{day: 21, title: `Duygular, tercihler ve fikirler`, title_native: `Gefühle, Vorlieben und Meinungen`, focus: `Münih’te yeni tanıştığın insanlarla sohbet ediyorsun. Bugün beğenmek, istemek, sevmemek ve basit fikir belirtmeyi öğreneceksin.`, vocab: [{de: `gut`, tr: `iyi`, ipa: `guut`},{de: `schlecht`, tr: `kötü`, ipa: `şleht`},{de: `schön`, tr: `güzel`, ipa: `şön`},{de: `interessant`, tr: `ilginç`, ipa: `in-te-re-sant`},{de: `langweilig`, tr: `sıkıcı`, ipa: `lang-vay-lih`},{de: `müde`, tr: `yorgun`, ipa: `müü-dı`},{de: `glücklich`, tr: `mutlu`, ipa: `glük-lih`},{de: `hungrig`, tr: `aç`, ipa: `hung-rih`},{de: `durstig`, tr: `susamış`, ipa: `durst-ih`},{de: `Lieblings-`, tr: `favori`, ipa: `liip-lings`}], phrases: [{de: `Ich mag Berlin.`, tr: `Berlin’i seviyorum.`, ipa: `ih maak ber-liin`},{de: `Ich mag das nicht.`, tr: `Bunu sevmiyorum.`, ipa: `ih maak das niht`},{de: `Das ist interessant.`, tr: `Bu ilginç.`, ipa: `das ist in-te-re-sant`},{de: `Ich bin müde.`, tr: `Yorgunum.`, ipa: `ih bin müü-dı`},{de: `Ich habe Hunger.`, tr: `Açım.`, ipa: `ih haa-bı hung-ır`},{de: `Was ist dein Lieblingsessen?`, tr: `En sevdiğin yemek ne?`, ipa: `vas ist dayn liip-lings-es-ın`}], grammar: `“mögen” beğenmek veya sevmek anlamındadır; “Ich mag...” çok kolay bir fikir cümlesidir. Açlık için Almancada “Ich habe Hunger” denir, kelime kelime “açlığım var” gibi düşün. Duygular için çoğu zaman “Ich bin...” kullanılır: “Ich bin müde.”`, practice: [`“Berlin’i seviyorum” cümlesini başka bir şehirle değiştir.`,`“Bunu sevmiyorum” ifadesini söyle.`,`Aç olduğunu Almanca ifade et.`,`“En sevdiğin yemek ne?” sorusunu tekrar et.`,`Bugünkü ruh halini Almanca bir cümleyle yaz.`]},{day: 22, title: `Yerel insanlarla küçük sohbet`, title_native: `Small Talk mit Einheimischen`, focus: `Viyana’da bir parkta veya kafede yerel biriyle kısa sohbet ediyorsun. Bugün hava, şehir, seyahat ve basit iltifatlar hakkında konuşmayı öğreneceksin.`, vocab: [{de: `Einheimische`, tr: `yerel kişi`, ipa: `ayn-hay-mi-şı`},{de: `Reise`, tr: `seyahat`, ipa: `ray-zı`},{de: `Urlaub`, tr: `tatil`, ipa: `uur-laup`},{de: `Stadt`, tr: `şehir`, ipa: `ştat`},{de: `schön`, tr: `güzel`, ipa: `şön`},{de: `ruhig`, tr: `sakin`, ipa: `ruu-ih`},{de: `laut`, tr: `gürültülü`, ipa: `laut`},{de: `freundlich`, tr: `arkadaş canlısı`, ipa: `froynt-lih`},{de: `oft`, tr: `sık sık`, ipa: `oft`},{de: `manchmal`, tr: `bazen`, ipa: `manh-mal`}], phrases: [{de: `Sind Sie von hier?`, tr: `Buralı mısınız?`, ipa: `zint zi fon hiir`},{de: `Ich bin im Urlaub.`, tr: `Tatildeyim.`, ipa: `ih bin im uur-laup`},{de: `Die Stadt ist sehr schön.`, tr: `Şehir çok güzel.`, ipa: `di ştat ist zeer şön`},{de: `Die Leute sind freundlich.`, tr: `İnsanlar arkadaş canlısı.`, ipa: `di loy-tı zint froynt-lih`},{de: `Kommen Sie oft hierher?`, tr: `Buraya sık sık gelir misiniz?`, ipa: `ko-mın zi oft hiir-her`},{de: `Ich lerne Deutsch.`, tr: `Almanca öğreniyorum.`, ipa: `ih ler-nı doytş`}], grammar: `Küçük sohbetlerde basit cümleler en doğal olanıdır. “sehr” çok anlamına gelir ve sıfatlardan önce kullanılır: “sehr schön”, “sehr freundlich”. “Ich lerne Deutsch” demek, konuşma pratiği istediğini kibarca gösterir.`, practice: [`“Tatildeyim” cümlesini Almanca söyle.`,`“Şehir çok güzel” ifadesini yaz.`,`“Buralı mısınız?” sorusunu tekrar et.`,`Kendi bulunduğun şehir için Almanca bir iltifat cümlesi kur.`,`Yerel biriyle üç satırlık küçük sohbet yaz.`]},{day: 23, title: `Daha ayrıntılı yemek ve içecek siparişi`, title_native: `Detaillierter Essen und Getränke bestellen`, focus: `Köln’de yoğun bir restoranda özel isteklerin var. Bugün pişirme tercihi, garnitür, içecek ve hesabı bölüşme ifadelerini öğreneceksin.`, vocab: [{de: `Getränk`, tr: `içecek`, ipa: `gı-trenk`},{de: `Vorspeise`, tr: `başlangıç`, ipa: `foor-şpay-zı`},{de: `Hauptgericht`, tr: `ana yemek`, ipa: `haupt-gı-riht`},{de: `Nachspeise`, tr: `tatlı`, ipa: `nah-şpay-zı`},{de: `Beilage`, tr: `garnitür`, ipa: `bay-la-gı`},{de: `ohne`, tr: `olmadan / -siz`, ipa: `oo-nı`},{de: `extra`, tr: `ekstra`, ipa: `eks-tra`},{de: `zusammen`, tr: `birlikte`, ipa: `tsu-za-mın`},{de: `getrennt`, tr: `ayrı`, ipa: `gı-trent`},{de: `Trinkgeld`, tr: `bahşiş`, ipa: `trink-gelt`}], phrases: [{de: `Wir möchten bestellen.`, tr: `Sipariş vermek istiyoruz.`, ipa: `viir möh-tın bı-ştel-ın`},{de: `Ohne Zwiebeln, bitte.`, tr: `Soğansız olsun, lütfen.`, ipa: `oo-nı tsvi-bıln bi-tı`},{de: `Extra Sauce, bitte.`, tr: `Ekstra sos, lütfen.`, ipa: `eks-tra zo-sı bi-tı`},{de: `Können wir getrennt zahlen?`, tr: `Ayrı ödeyebilir miyiz?`, ipa: `kön-nın viir gı-trent tsa-lın`},{de: `Alles zusammen, bitte.`, tr: `Hepsi birlikte, lütfen.`, ipa: `a-lıs tsu-za-mın bi-tı`},{de: `Stimmt so.`, tr: `Üstü kalsın.`, ipa: `ştimt zo`}], grammar: `“ohne” ve “extra” restoranlarda özel istek belirtmek için çok kullanılır. Hesapta “getrennt zahlen” ayrı ödemek, “zusammen zahlen” birlikte ödemek demektir. Bahşiş verirken “Stimmt so” demek para üstünü istemediğini gösterir.`, practice: [`“Soğansız olsun, lütfen” cümlesini Almanca yaz.`,`“Ayrı ödeyebilir miyiz?” sorusunu söyle.`,`“Ekstra sos” ile yeni bir sipariş cümlesi kur.`,`“Üstü kalsın” ifadesini ezberle.`,`Restoranda özel istek içeren dört satırlık diyalog yaz.`]},{day: 24, title: `Şikâyet, sorun çözme ve nazik itiraz`, title_native: `Beschwerden, Problemlösung und höflicher Widerspruch`, focus: `Otelde oda soğuk, restoranda sipariş yanlış veya mağazada ürün bozuk olabilir. Bugün nazikçe sorun bildirmeyi ve çözüm istemeyi öğreneceksin.`, vocab: [{de: `Problem`, tr: `sorun`, ipa: `pro-bleem`},{de: `falsch`, tr: `yanlış`, ipa: `falş`},{de: `richtig`, tr: `doğru`, ipa: `rih-tih`},{de: `kalt`, tr: `soğuk`, ipa: `kalt`},{de: `warm`, tr: `sıcak`, ipa: `varm`},{de: `laut`, tr: `gürültülü`, ipa: `laut`},{de: `kaputt`, tr: `bozuk`, ipa: `ka-put`},{de: `schmutzig`, tr: `kirli`, ipa: `şmut-sih`},{de: `Lösung`, tr: `çözüm`, ipa: `lö-zung`},{de: `Entschuldigung`, tr: `affedersiniz`, ipa: `ent-şul-di-gung`}], phrases: [{de: `Entschuldigung, es gibt ein Problem.`, tr: `Affedersiniz, bir sorun var.`, ipa: `ent-şul-di-gung es gibt ayn pro-bleem`},{de: `Das ist nicht richtig.`, tr: `Bu doğru değil.`, ipa: `das ist niht rih-tih`},{de: `Mein Zimmer ist zu laut.`, tr: `Odam çok gürültülü.`, ipa: `mayn tsi-mır ist tsu laut`},{de: `Das Essen ist kalt.`, tr: `Yemek soğuk.`, ipa: `das es-ın ist kalt`},{de: `Können Sie das bitte prüfen?`, tr: `Bunu lütfen kontrol edebilir misiniz?`, ipa: `kön-nın zi das bi-tı prü-fın`},{de: `Gibt es eine andere Lösung?`, tr: `Başka bir çözüm var mı?`, ipa: `gibt es ay-nı an-dı-rı lö-zung`}], grammar: `Nazik şikâyetlerde önce “Entschuldigung” demek tonu yumuşatır. “zu” sıfattan önce gelince “fazla/çok” anlamı verir: “zu laut”, “zu kalt”. Çözüm isterken “Können Sie...?” resmi ve güvenli bir kalıptır.`, practice: [`“Bir sorun var” cümlesini Almanca söyle.`,`“Bu doğru değil” ifadesini yaz.`,`“Odam çok gürültülü” cümlesini kur.`,`Bir çalışana “Bunu kontrol edebilir misiniz?” diye sor.`,`Otelde yaşanan bir sorunu Almanca üç cümleyle açıkla.`]},{day: 25, title: `Banka, para çekme ve ödeme sorunları`, title_native: `Bank, Geld abheben und Zahlungsprobleme`, focus: `Frankfurt’ta ATM kullanman veya kart sorunu çözmen gerekiyor. Bugün para, banka, ATM ve ödeme hataları için ifadeler öğreneceksin.`, vocab: [{de: `Bank`, tr: `banka`, ipa: `bank`},{de: `Geld`, tr: `para`, ipa: `gelt`},{de: `Geldautomat`, tr: `ATM`, ipa: `gelt-au-to-maat`},{de: `Karte`, tr: `kart`, ipa: `kar-tı`},{de: `Bargeld`, tr: `nakit`, ipa: `baar-gelt`},{de: `Konto`, tr: `hesap`, ipa: `kon-to`},{de: `Gebühr`, tr: `ücret / komisyon`, ipa: `gı-büür`},{de: `Quittung`, tr: `fiş / makbuz`, ipa: `kvi-tung`},{de: `bezahlen`, tr: `ödemek`, ipa: `bı-tsaa-lın`},{de: `abheben`, tr: `para çekmek`, ipa: `ap-hee-bın`}], phrases: [{de: `Wo ist der nächste Geldautomat?`, tr: `En yakın ATM nerede?`, ipa: `vo ist der nek-stı gelt-au-to-maat`},{de: `Ich möchte Geld abheben.`, tr: `Para çekmek istiyorum.`, ipa: `ih möh-tı gelt ap-hee-bın`},{de: `Meine Karte funktioniert nicht.`, tr: `Kartım çalışmıyor.`, ipa: `may-nı kar-tı funk-tsyo-niirt niht`},{de: `Kann ich bar bezahlen?`, tr: `Nakit ödeyebilir miyim?`, ipa: `kan ih baar bı-tsaa-lın`},{de: `Ich brauche eine Quittung.`, tr: `Makbuza ihtiyacım var.`, ipa: `ih brau-hı ay-nı kvi-tung`},{de: `Gibt es eine Gebühr?`, tr: `Komisyon var mı?`, ipa: `gibt es ay-nı gı-büür`}], grammar: `“Möchte” yine nazik istek için kullanılır: “Ich möchte Geld abheben.” Ödeme sorunlarında “funktioniert nicht” çok yararlıdır; cihaz, kart veya uygulama çalışmadığında kullanılabilir. “nächste” en yakın anlamına gelir.`, practice: [`“En yakın ATM nerede?” cümlesini yaz.`,`“Kartım çalışmıyor” ifadesini söyle.`,`“Nakit ödeyebilir miyim?” sorusunu tekrar et.`,`“Komisyon var mı?” cümlesini kur.`,`ATM veya mağaza ödeme sorunu için kısa bir diyalog yaz.`]},{day: 26, title: `Telefon, internet ve bağlantı`, title_native: `Telefon, Internet und Verbindung`, focus: `Zürih’te SIM kart almak veya Wi-Fi bağlantısı sormak istiyorsun. Bugün internet, şifre, telefon ve teknik sorunlarla ilgili ifadeleri öğreneceksin.`, vocab: [{de: `Internet`, tr: `internet`, ipa: `in-ter-net`},{de: `WLAN`, tr: `Wi-Fi`, ipa: `ve-lan`},{de: `Passwort`, tr: `şifre`, ipa: `pas-vort`},{de: `Verbindung`, tr: `bağlantı`, ipa: `fer-bin-dung`},{de: `SIM-Karte`, tr: `SIM kart`, ipa: `zim-kar-tı`},{de: `Daten`, tr: `veri / internet paketi`, ipa: `daa-tın`},{de: `Akku`, tr: `pil`, ipa: `a-ku`},{de: `Ladegerät`, tr: `şarj cihazı`, ipa: `laa-dı-gı-ret`},{de: `Nachricht`, tr: `mesaj`, ipa: `nah-riht`},{de: `Anruf`, tr: `arama`, ipa: `an-ruuf`}], phrases: [{de: `Wie ist das WLAN-Passwort?`, tr: `Wi-Fi şifresi nedir?`, ipa: `vi ist das ve-lan pas-vort`},{de: `Ich brauche eine SIM-Karte.`, tr: `Bir SIM karta ihtiyacım var.`, ipa: `ih brau-hı ay-nı zim-kar-tı`},{de: `Mein Akku ist leer.`, tr: `Pilim bitti.`, ipa: `mayn a-ku ist leer`},{de: `Haben Sie ein Ladegerät?`, tr: `Şarj cihazınız var mı?`, ipa: `haa-bın zi ayn laa-dı-gı-ret`},{de: `Die Verbindung ist schlecht.`, tr: `Bağlantı kötü.`, ipa: `di fer-bin-dung ist şleht`},{de: `Ich kann nicht anrufen.`, tr: `Arama yapamıyorum.`, ipa: `ih kan niht an-ruu-fın`}], grammar: `Teknik sorunlarda “Ich kann nicht...” çok önemlidir ve “... yapamıyorum” anlamına gelir. “Mein Akku ist leer” Almancada pilin bittiğini söylemenin doğal yoludur. Wi-Fi şifresi sorarken “Wie ist...?” kullanılır.`, practice: [`“Wi-Fi şifresi nedir?” cümlesini Almanca yaz.`,`“Pilim bitti” ifadesini söyle.`,`“Bir SIM karta ihtiyacım var” cümlesini kur.`,`“Arama yapamıyorum” ifadesini tekrar et.`,`Telefon mağazasında geçecek dört satırlık kısa diyalog yaz.`]},{day: 27, title: `Sınır, pasaport ve havaalanı`, title_native: `Grenze, Pass und Flughafen`, focus: `Almanya’ya uçakla geldin veya Avusturya’dan İsviçre’ye geçiyorsun. Bugün havaalanı, pasaport kontrolü ve bagaj ifadelerini öğreneceksin.`, vocab: [{de: `Flughafen`, tr: `havaalanı`, ipa: `fluuk-haa-fın`},{de: `Passkontrolle`, tr: `pasaport kontrolü`, ipa: `pas-kon-tro-lı`},{de: `Gepäck`, tr: `bagaj`, ipa: `gı-pek`},{de: `Koffer`, tr: `bavul`, ipa: `ko-fır`},{de: `Handgepäck`, tr: `el bagajı`, ipa: `hant-gı-pek`},{de: `Flug`, tr: `uçuş`, ipa: `fluuk`},{de: `Ankunft`, tr: `varış`, ipa: `an-kunft`},{de: `Abflug`, tr: `kalkış`, ipa: `ap-fluuk`},{de: `Tor`, tr: `kapı`, ipa: `toor`},{de: `Zoll`, tr: `gümrük`, ipa: `tsol`}], phrases: [{de: `Wo ist die Passkontrolle?`, tr: `Pasaport kontrolü nerede?`, ipa: `vo ist di pas-kon-tro-lı`},{de: `Ich habe nur Handgepäck.`, tr: `Sadece el bagajım var.`, ipa: `ih haa-bı nuur hant-gı-pek`},{de: `Mein Koffer fehlt.`, tr: `Bavulum eksik / kayıp.`, ipa: `mayn ko-fır feelt`},{de: `Wann ist der Abflug?`, tr: `Kalkış ne zaman?`, ipa: `van ist der ap-fluuk`},{de: `Welches Tor?`, tr: `Hangi kapı?`, ipa: `vel-hes toor`},{de: `Ich bin Tourist.`, tr: `Turistim.`, ipa: `ih bin tu-rist`}], grammar: `Havaalanında kısa sorular çok yaygındır: “Welches Tor?” gibi. “nur” sadece anlamına gelir ve “Ich habe nur Handgepäck” cümlesinde çok kullanışlıdır. Pasaport kontrolünde “Ich bin Tourist” kısa ve anlaşılır bir cevaptır.`, practice: [`“Pasaport kontrolü nerede?” sorusunu yaz.`,`“Sadece el bagajım var” cümlesini söyle.`,`“Bavulum kayıp” ifadesini tekrar et.`,`“Kalkış ne zaman?” cümlesini kur.`,`Havaalanı görevlisine soracağın üç soru yaz.`]},{day: 28, title: `Davetler, buluşmalar ve sosyal planlar`, title_native: `Einladungen, Treffen und soziale Pläne`, focus: `Berlin’de tanıştığın biri seni akşam dışarı davet ediyor. Bugün davet kabul etme, reddetme, saat ve yer belirleme ifadelerini öğreneceksin.`, vocab: [{de: `Treffen`, tr: `buluşma`, ipa: `tre-fın`},{de: `Einladung`, tr: `davet`, ipa: `ayn-laa-dung`},{de: `heute Abend`, tr: `bu akşam`, ipa: `hoy-tı aa-bınt`},{de: `morgen`, tr: `yarın`, ipa: `mor-gın`},{de: `später`, tr: `sonra`, ipa: `şpee-tır`},{de: `gern`, tr: `memnuniyetle`, ipa: `gern`},{de: `leider`, tr: `maalesef`, ipa: `lay-dır`},{de: `vielleicht`, tr: `belki`, ipa: `fi-layht`},{de: `Ort`, tr: `yer`, ipa: `ort`},{de: `Zeit`, tr: `zaman`, ipa: `tsayt`}], phrases: [{de: `Möchtest du etwas trinken gehen?`, tr: `Bir şeyler içmeye gitmek ister misin?`, ipa: `möh-test du et-vas trin-kın gee-ın`},{de: `Gern, warum nicht?`, tr: `Memnuniyetle, neden olmasın?`, ipa: `gern va-rum niht`},{de: `Leider habe ich keine Zeit.`, tr: `Maalesef vaktim yok.`, ipa: `lay-dır haa-bı ih kay-nı tsayt`},{de: `Wann treffen wir uns?`, tr: `Ne zaman buluşuyoruz?`, ipa: `van tre-fın viir uns`},{de: `Wo treffen wir uns?`, tr: `Nerede buluşuyoruz?`, ipa: `vo tre-fın viir uns`},{de: `Bis später!`, tr: `Sonra görüşürüz!`, ipa: `bis şpee-tır`}], grammar: `Arkadaşça konuşmalarda “du” kullanılır. “Möchtest du...?” kibar ama samimi bir davet kalıbıdır. Reddederken “Leider...” ile başlamak nazik bir ton verir.`, practice: [`“Bir şeyler içmeye gitmek ister misin?” cümlesini söyle.`,`Daveti kabul etmek için kısa bir cevap yaz.`,`Nazikçe reddetmek için “Maalesef...” ile cümle kur.`,`“Nerede buluşuyoruz?” sorusunu tekrar et.`,`Bir sosyal plan için beş satırlık Almanca mini diyalog yaz.`]},{day: 29, title: `Geçmiş deneyimleri anlatma`, title_native: `Über vergangene Erlebnisse sprechen`, focus: `Seyahatin sonunda neler yaptığını anlatıyorsun. Bugün “gördüm, yedim, gittim, aldım” gibi basit geçmiş anlatımlarını öğreneceksin.`, vocab: [{de: `gesehen`, tr: `görmüş / gördü`, ipa: `gı-zee-ın`},{de: `gegessen`, tr: `yemiş / yedi`, ipa: `gı-ges-ın`},{de: `getrunken`, tr: `içmiş / içti`, ipa: `gı-trun-kın`},{de: `gekauft`, tr: `satın almış / aldı`, ipa: `gı-kauft`},{de: `gemacht`, tr: `yapmış / yaptı`, ipa: `gı-maht`},{de: `besucht`, tr: `ziyaret etmiş`, ipa: `bı-zuuht`},{de: `gefahren`, tr: `gitmiş / araçla gitmiş`, ipa: `gı-faa-rın`},{de: `gestern`, tr: `dün`, ipa: `ges-tırn`},{de: `letzte Woche`, tr: `geçen hafta`, ipa: `lets-tı vo-hı`},{de: `schon`, tr: `zaten / daha önce`, ipa: `şoon`}], phrases: [{de: `Ich habe Berlin besucht.`, tr: `Berlin’i ziyaret ettim.`, ipa: `ih haa-bı ber-liin bı-zuuht`},{de: `Ich habe Kaffee getrunken.`, tr: `Kahve içtim.`, ipa: `ih haa-bı ka-fe gı-trun-kın`},{de: `Ich habe ein Geschenk gekauft.`, tr: `Bir hediye aldım.`, ipa: `ih haa-bı ayn gı-şenk gı-kauft`},{de: `Gestern habe ich viel gemacht.`, tr: `Dün çok şey yaptım.`, ipa: `ges-tırn haa-bı ih fiil gı-maht`},{de: `Ich bin nach München gefahren.`, tr: `Münih’e gittim.`, ipa: `ih bin nah mün-hın gı-faa-rın`},{de: `Das habe ich schon gesehen.`, tr: `Bunu daha önce gördüm.`, ipa: `das haa-bı ih şoon gı-zee-ın`}], grammar: `Günlük konuşmada geçmiş zaman için genellikle “haben + geçmiş fiil” kullanılır: “Ich habe Kaffee getrunken.” Hareket fiillerinde bazen “sein” kullanılır: “Ich bin nach München gefahren.” İlk aşamada bu kalıpları ezberlemek, kuralı uzun uzun öğrenmekten daha pratiktir.`, practice: [`“Berlin’i ziyaret ettim” cümlesini başka bir şehirle değiştir.`,`“Kahve içtim” cümlesini yaz.`,`“Bir hediye aldım” ifadesini söyle.`,`Dün yaptığın üç şeyi Almanca basit cümlelerle anlat.`,`“Bunu daha önce gördüm” cümlesini tekrar et.`]},{day: 30, title: `Seyahat sonu, vedalaşma ve genel tekrar`, title_native: `Reiseende, Abschied und Wiederholung`, focus: `Almanca konuşulan bir ülkedeki seyahatinin son günündesin. Bugün vedalaşma, teşekkür etme, deneyimini anlatma ve en önemli ifadeleri tekrar edeceksin.`, vocab: [{de: `Abschied`, tr: `veda`, ipa: `ap-şiit`},{de: `Reise`, tr: `seyahat`, ipa: `ray-zı`},{de: `Erfahrung`, tr: `deneyim`, ipa: `er-faa-rung`},{de: `wunderbar`, tr: `harika`, ipa: `vun-dır-baar`},{de: `noch einmal`, tr: `tekrar / bir kez daha`, ipa: `noh ayn-mal`},{de: `zurück`, tr: `geri`, ipa: `tsu-rük`},{de: `bald`, tr: `yakında`, ipa: `balt`},{de: `Erinnerung`, tr: `anı`, ipa: `er-in-nı-rung`},{de: `dankbar`, tr: `minnettar`, ipa: `dank-baar`},{de: `wieder`, tr: `yeniden`, ipa: `vii-dır`}], phrases: [{de: `Danke für alles.`, tr: `Her şey için teşekkürler.`, ipa: `dan-kı für a-lıs`},{de: `Die Reise war wunderbar.`, tr: `Seyahat harikaydı.`, ipa: `di ray-zı vaar vun-dır-baar`},{de: `Ich komme bald zurück.`, tr: `Yakında geri geleceğim.`, ipa: `ih ko-mı balt tsu-rük`},{de: `Ich habe viel gelernt.`, tr: `Çok şey öğrendim.`, ipa: `ih haa-bı fiil gı-lernt`},{de: `Es war schön, Sie kennenzulernen.`, tr: `Sizinle tanışmak güzeldi.`, ipa: `es vaar şön zi ke-nın-tsu-ler-nın`},{de: `Auf Wiedersehen!`, tr: `Hoşça kalın!`, ipa: `auf vii-dır-zee-ın`}], grammar: `Resmi vedalarda “Auf Wiedersehen” güvenli ve nazik bir ifadedir. “Es war schön...” geçmişte güzel bir deneyimi anlatmak için kullanılır. Seyahat sonunda “Ich habe...” kalıbıyla öğrendiklerini, gördüklerini ve yaptıklarını özetleyebilirsin.`, practice: [`“Her şey için teşekkürler” cümlesini Almanca söyle.`,`“Seyahat harikaydı” ifadesini yaz.`,`“Yakında geri geleceğim” cümlesini tekrar et.`,`Bu kursta öğrendiğin beş önemli Almanca ifadeyi listele.`,`Seyahatinin son gününde kullanacağın kısa bir veda konuşması yaz.`]}];

var CONVERSATIONS_TR_DE = [{id: 1, title: `Kafede kahve siparişi`, scene: `Berlin’de küçük bir kafeye giriyorsun. Barista seni karşılıyor ve sen kahve ile küçük bir tatlı sipariş etmek istiyorsun.`, lines: [{who: `them`, de: `Guten Morgen, was möchten Sie?`, tr: `Günaydın, ne istersiniz?`},{who: `you`, de: `Guten Morgen, einen Kaffee, bitte.`, tr: `Günaydın, bir kahve lütfen.`},{who: `them`, de: `Mit Milch oder ohne Milch?`, tr: `Sütlü mü sütsüz mü?`},{who: `you`, de: `Mit Milch, bitte, aber ohne Zucker.`, tr: `Sütlü olsun lütfen, ama şekersiz.`},{who: `them`, de: `Möchten Sie auch etwas essen?`, tr: `Bir şey yemek de ister misiniz?`},{who: `you`, de: `Ja, ein Stück Kuchen, bitte.`, tr: `Evet, bir dilim kek lütfen.`},{who: `them`, de: `Das macht sechs Euro.`, tr: `Toplam altı euro.`},{who: `you`, de: `Kann ich mit Karte zahlen?`, tr: `Kartla ödeyebilir miyim?`},{who: `them`, de: `Ja, natürlich.`, tr: `Evet, tabii.`},{who: `you`, de: `Danke schön.`, tr: `Çok teşekkürler.`},{who: `them`, de: `Bitte schön, einen schönen Tag!`, tr: `Rica ederim, iyi günler!`},{who: `you`, de: `Danke, ebenfalls!`, tr: `Teşekkürler, size de!`}]},{id: 2, title: `Otelde giriş`, scene: `Münih’te oteline varıyorsun ve resepsiyonda rezervasyonunu söylüyorsun. Odanın nerede olduğunu ve kahvaltı saatini öğrenmek istiyorsun.`, lines: [{who: `them`, de: `Guten Abend, willkommen im Hotel.`, tr: `İyi akşamlar, otele hoş geldiniz.`},{who: `you`, de: `Guten Abend, ich habe eine Reservierung.`, tr: `İyi akşamlar, rezervasyonum var.`},{who: `them`, de: `Auf welchen Namen, bitte?`, tr: `Hangi isim adına, lütfen?`},{who: `you`, de: `Auf den Namen Yılmaz.`, tr: `Yılmaz adına.`},{who: `them`, de: `Einen Moment, bitte. Ja, ein Zimmer für zwei Nächte.`, tr: `Bir dakika lütfen. Evet, iki gecelik bir oda.`},{who: `you`, de: `Kann ich jetzt einchecken?`, tr: `Şimdi giriş yapabilir miyim?`},{who: `them`, de: `Ja, natürlich, hier ist Ihr Schlüssel.`, tr: `Evet tabii, anahtarınız burada.`},{who: `you`, de: `Danke, wo ist mein Zimmer?`, tr: `Teşekkürler, odam nerede?`},{who: `them`, de: `Im zweiten Stock, der Aufzug ist rechts.`, tr: `İkinci katta, asansör sağda.`},{who: `you`, de: `Wann ist Frühstück?`, tr: `Kahvaltı ne zaman?`},{who: `them`, de: `Frühstück ist von sieben bis zehn Uhr.`, tr: `Kahvaltı saat yediden ona kadar.`},{who: `you`, de: `Perfekt, danke für Ihre Hilfe.`, tr: `Harika, yardımınız için teşekkürler.`}]},{id: 3, title: `Yol tarifi sorma`, scene: `Viyana’da şehir merkezinde yürüyorsun ama müzeyi bulamıyorsun. Yoldan geçen birine kibarca yön soruyorsun.`, lines: [{who: `you`, de: `Entschuldigung, können Sie mir helfen?`, tr: `Affedersiniz, bana yardım edebilir misiniz?`},{who: `them`, de: `Ja, natürlich.`, tr: `Evet, tabii.`},{who: `you`, de: `Wo ist das Kunstmuseum?`, tr: `Sanat müzesi nerede?`},{who: `them`, de: `Gehen Sie geradeaus und dann links.`, tr: `Dümdüz gidin ve sonra sola dönün.`},{who: `you`, de: `Ist es weit?`, tr: `Uzak mı?`},{who: `them`, de: `Nein, es ist in der Nähe.`, tr: `Hayır, yakında.`},{who: `you`, de: `Wie viele Minuten zu Fuß?`, tr: `Yürüyerek kaç dakika?`},{who: `them`, de: `Ungefähr fünf Minuten.`, tr: `Yaklaşık beş dakika.`},{who: `you`, de: `Danke schön.`, tr: `Çok teşekkürler.`},{who: `them`, de: `Bitte, gern.`, tr: `Rica ederim, memnuniyetle.`},{who: `you`, de: `Einen schönen Tag!`, tr: `İyi günler!`},{who: `them`, de: `Ihnen auch!`, tr: `Size de!`}]},{id: 4, title: `Restoranda akşam yemeği`, scene: `Köln’de bir restorandasın ve garson sipariş almaya geliyor. Vejetaryen seçenek sormak, yemeğini seçmek ve hesabı istemek istiyorsun.`, lines: [{who: `them`, de: `Guten Abend, möchten Sie bestellen?`, tr: `İyi akşamlar, sipariş vermek ister misiniz?`},{who: `you`, de: `Ja, die Speisekarte, bitte.`, tr: `Evet, menü lütfen.`},{who: `them`, de: `Natürlich, hier bitte.`, tr: `Tabii, buyurun.`},{who: `you`, de: `Haben Sie etwas Vegetarisches?`, tr: `Vejetaryen bir şeyiniz var mı?`},{who: `them`, de: `Ja, wir haben Suppe, Salat und Gemüse mit Reis.`, tr: `Evet, çorba, salata ve pilavlı sebzemiz var.`},{who: `you`, de: `Ich nehme Gemüse mit Reis.`, tr: `Pilavlı sebze alıyorum.`},{who: `them`, de: `Möchten Sie etwas trinken?`, tr: `Bir şey içmek ister misiniz?`},{who: `you`, de: `Ein Wasser, bitte.`, tr: `Bir su lütfen.`},{who: `them`, de: `Sehr gern.`, tr: `Memnuniyetle.`},{who: `you`, de: `Das war sehr lecker, die Rechnung bitte.`, tr: `Çok lezzetliydi, hesap lütfen.`},{who: `them`, de: `Natürlich, das macht vierzehn Euro.`, tr: `Tabii, toplam on dört euro.`},{who: `you`, de: `Stimmt so, danke.`, tr: `Üstü kalsın, teşekkürler.`}]},{id: 5, title: `Tren bileti alma`, scene: `Zürich ana tren istasyonundasın ve Luzern’e gitmek istiyorsun. Bilet gişesinde direkt tren, saat ve peron hakkında bilgi alıyorsun.`, lines: [{who: `them`, de: `Guten Tag, wie kann ich Ihnen helfen?`, tr: `İyi günler, size nasıl yardım edebilirim?`},{who: `you`, de: `Ich möchte nach Luzern fahren.`, tr: `Luzern’e gitmek istiyorum.`},{who: `them`, de: `Einfach oder hin und zurück?`, tr: `Tek yön mü gidiş dönüş mü?`},{who: `you`, de: `Hin und zurück, bitte.`, tr: `Gidiş dönüş lütfen.`},{who: `them`, de: `Möchten Sie einen direkten Zug?`, tr: `Direkt tren ister misiniz?`},{who: `you`, de: `Ja, gibt es einen direkten Zug?`, tr: `Evet, direkt tren var mı?`},{who: `them`, de: `Ja, der nächste Zug fährt um elf Uhr.`, tr: `Evet, sonraki tren saat on birde kalkıyor.`},{who: `you`, de: `Von welchem Gleis?`, tr: `Hangi perondan?`},{who: `them`, de: `Von Gleis fünf.`, tr: `Beşinci perondan.`},{who: `you`, de: `Ist das Ticket heute gültig?`, tr: `Bilet bugün geçerli mi?`},{who: `them`, de: `Ja, den ganzen Tag.`, tr: `Evet, bütün gün.`},{who: `you`, de: `Danke schön.`, tr: `Çok teşekkürler.`}]},{id: 6, title: `Mağazada alışveriş`, scene: `Hamburg’da bir mağazada hediye bakıyorsun. Renk, fiyat ve ödeme konusunda soru soruyorsun.`, lines: [{who: `them`, de: `Hallo, kann ich Ihnen helfen?`, tr: `Merhaba, size yardımcı olabilir miyim?`},{who: `you`, de: `Ja, ich suche ein Geschenk.`, tr: `Evet, bir hediye arıyorum.`},{who: `them`, de: `Für wen ist das Geschenk?`, tr: `Hediye kimin için?`},{who: `you`, de: `Für meine Freundin.`, tr: `Kız arkadaşım için.`},{who: `them`, de: `Vielleicht diese Tasche?`, tr: `Belki bu çanta?`},{who: `you`, de: `Haben Sie das in Schwarz?`, tr: `Bunun siyahı var mı?`},{who: `them`, de: `Ja, einen Moment bitte.`, tr: `Evet, bir dakika lütfen.`},{who: `you`, de: `Wie viel kostet das?`, tr: `Bu ne kadar?`},{who: `them`, de: `Das kostet fünfunddreißig Euro.`, tr: `Bu otuz beş euro.`},{who: `you`, de: `Gut, ich nehme das.`, tr: `Tamam, bunu alıyorum.`},{who: `them`, de: `Zahlen Sie bar oder mit Karte?`, tr: `Nakit mi kartla mı ödersiniz?`},{who: `you`, de: `Mit Karte, bitte.`, tr: `Kartla lütfen.`}]},{id: 7, title: `Eczanede yardım isteme`, scene: `Salzburg’da gezerken başın ağrıyor. Bir eczaneye girip uygun bir ilaç ve kullanım bilgisi sormak istiyorsun.`, lines: [{who: `them`, de: `Guten Tag, was brauchen Sie?`, tr: `İyi günler, neye ihtiyacınız var?`},{who: `you`, de: `Guten Tag, ich habe Kopfschmerzen.`, tr: `İyi günler, başım ağrıyor.`},{who: `them`, de: `Seit wann haben Sie die Schmerzen?`, tr: `Ne zamandan beri ağrınız var?`},{who: `you`, de: `Seit heute Morgen.`, tr: `Bu sabahtan beri.`},{who: `them`, de: `Haben Sie eine Allergie?`, tr: `Alerjiniz var mı?`},{who: `you`, de: `Nein, keine Allergie.`, tr: `Hayır, alerjim yok.`},{who: `them`, de: `Diese Tabletten können helfen.`, tr: `Bu tabletler yardımcı olabilir.`},{who: `you`, de: `Wie oft nehme ich sie?`, tr: `Ne sıklıkla almalıyım?`},{who: `them`, de: `Eine Tablette mit Wasser, maximal dreimal am Tag.`, tr: `Su ile bir tablet, günde en fazla üç kez.`},{who: `you`, de: `Danke, wie viel kostet das?`, tr: `Teşekkürler, ne kadar?`},{who: `them`, de: `Acht Euro fünfzig.`, tr: `Sekiz euro elli.`},{who: `you`, de: `Danke schön.`, tr: `Çok teşekkürler.`}]},{id: 8, title: `Yerel biriyle küçük sohbet`, scene: `Berlin’de bir parkta bankta oturuyorsun. Yanındaki kişi sohbet başlatıyor ve sen Almanca pratik yapmaya çalışıyorsun.`, lines: [{who: `you`, de: `Entschuldigung, ist dieser Platz frei?`, tr: `Affedersiniz, bu yer boş mu?`},{who: `them`, de: `Ja, natürlich.`, tr: `Evet, tabii.`},{who: `you`, de: `Danke, ich lerne Deutsch.`, tr: `Teşekkürler, Almanca öğreniyorum.`},{who: `them`, de: `Wirklich? Sie sprechen schon gut.`, tr: `Gerçekten mi? Şimdiden iyi konuşuyorsunuz.`},{who: `you`, de: `Danke, aber ich verstehe nicht alles.`, tr: `Teşekkürler, ama her şeyi anlamıyorum.`},{who: `them`, de: `Kein Problem, ich spreche langsam.`, tr: `Sorun değil, yavaş konuşurum.`},{who: `you`, de: `Sind Sie von hier?`, tr: `Buralı mısınız?`},{who: `them`, de: `Ja, ich wohne in Berlin.`, tr: `Evet, Berlin’de yaşıyorum.`},{who: `you`, de: `Die Stadt ist sehr schön.`, tr: `Şehir çok güzel.`},{who: `them`, de: `Ja, aber manchmal ist sie laut.`, tr: `Evet, ama bazen gürültülü.`},{who: `you`, de: `Das stimmt, aber die Leute sind freundlich.`, tr: `Doğru, ama insanlar arkadaş canlısı.`},{who: `them`, de: `Willkommen in Berlin!`, tr: `Berlin’e hoş geldiniz!`}]}];